UPDATE transfer_application
to_dept_id = #{toDeptId}, to_position_id = #{toPositionId}, transfer_reason = #{transferReason}, effective_date = #{effectiveDate}, old_manager_approved = #{oldManagerApproved}, new_manager_approved = #{newManagerApproved}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT ta.*, e.name AS employee_name, fd.dept_name AS from_dept_name, td.dept_name AS to_dept_name, fp.position_name AS from_position_name, tp.position_name AS to_position_name, su.username AS submitter_name FROM transfer_application ta JOIN employee e ON ta.employee_id = e.id LEFT JOIN department fd ON ta.from_dept_id = fd.id LEFT JOIN department td ON ta.to_dept_id = td.id LEFT JOIN position fp ON ta.from_position_id = fp.id LEFT JOIN position tp ON ta.to_position_id = tp.id LEFT JOIN sys_user su ON ta.submitter_id = su.id
AND ta.status = #{status}
AND e.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ta.create_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM transfer_application ta JOIN employee e ON ta.employee_id = e.id
AND ta.status = #{status}
AND e.name LIKE CONCAT('%', #{keyword}, '%')
